// ── Avatar helper ──
const Avatar = ({ src, initials, color, size=38 }) => (
  src
    ? <div style={{ width:size, height:size, borderRadius:"50%", overflow:"hidden", border:`1.5px solid ${color}66`, flexShrink:0 }}><img src={src} alt={initials} style={{ width:"100%", height:"100%", objectFit:"cover" }}/></div>
    : <div style={{ width:size, height:size, borderRadius:"50%", background:`${color}22`, border:`1.5px solid ${color}44`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}><span style={{ color, fontWeight:700, fontSize:size*0.34 }}>{initials}</span></div>
);

const Phone = ({ children }) => (
  <div style={{
    width: IS_DESKTOP ? 393 : "100vw",
    height: IS_DESKTOP ? 852 : "100dvh",
    borderRadius: IS_DESKTOP ? 52 : 0,
    background:"#080a12",
    boxShadow: IS_DESKTOP ? "0 0 0 1px #1a2035,0 0 0 10px #0d0f18,0 0 0 11px #1a2035,0 50px 100px rgba(0,0,0,0.9)" : "none",
    overflow:"hidden", display:"flex", flexDirection:"column", position:"relative", fontFamily:"'Sora',sans-serif"
  }}>
    {children}
  </div>
);

const BottomNav = ({ active, onNav }) => (
  <div style={{ position:"absolute", bottom:0, left:0, right:0, height:86, background:"#080a12", borderTop:"1px solid #0f1220", display:"flex", alignItems:"flex-start", paddingTop:10, zIndex:10 }}>
    {[
      { k:"feed",    icon:(a)=>I.feed(a),   label:"Feed" },
      { k:"chat",    icon:(a)=>I.chat(a),   label:"Chat" },
      { k:"create",  icon:()=>(<div style={{ width:44,height:44,borderRadius:14,background:"linear-gradient(135deg,#1F6FEB,#0f4ab8)",display:"flex",alignItems:"center",justifyContent:"center",marginTop:-8,boxShadow:"0 4px 20px rgba(31,111,235,0.4)" }}>{I.plus()}</div>), label:"" },
      { k:"alerts",  icon:(a)=>I.bell(a),   label:"Alerts" },
      { k:"profile", icon:(a)=>I.person(a), label:"Profile" },
    ].map(item=>(
      <button key={item.k} onClick={()=>onNav(item.k)} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:4, background:"none", border:"none", cursor:"pointer", padding:0 }}>
        {item.icon(active===item.k)}
        {item.label&&<span style={{ color:active===item.k?"#1F6FEB":"#2e3d5a", fontSize:10, fontFamily:"DM Sans", fontWeight:500 }}>{item.label}</span>}
      </button>
    ))}
  </div>
);

// ── Skip + Back helpers ──
const SkipBtn = ({ onSkip }) => (
  <button onClick={onSkip} style={{ background:"none", border:"none", cursor:"pointer", color:"#2e3d5a", fontSize:11.5, fontFamily:"DM Sans", textDecoration:"underline", padding:"4px 0" }}>Skip in prototype</button>
);
const BackBtn = ({ onClick }) => (
  <button onClick={onClick} style={{ background:"none", border:"none", cursor:"pointer", display:"flex", alignItems:"center" }}>{I.back()}</button>
);
const StepDots = ({ total, current }) => (
  <div style={{ display:"flex", gap:6, justifyContent:"center", marginBottom:24 }}>
    {Array.from({length:total}).map((_,i)=>(
      <div key={i} style={{ width:i===current?20:7, height:7, borderRadius:4, background:i===current?"#1F6FEB":i<current?"#1F6FEB44":"#1a2035", transition:"all 0.3s" }}/>
    ))}
  </div>
);

const CommentsModal = ({ post, onClose }) => {
  const [text, setText] = useState("");
  const [comments, setComments] = useState(SAMPLE_COMMENTS.slice(0,3));
  const sendComment = () => { if(!text.trim()) return; setComments(p=>[{user:"You",initials:"ME",avatar:IMGS.avatar_me,color:"#1F6FEB",text:text.trim(),time:"Just now"},...p]); setText(""); };
  return (
    <div style={{ position:"absolute", inset:0, zIndex:50, display:"flex", flexDirection:"column" }}>
      <div style={{ flex:1, background:"rgba(8,10,18,0.7)", backdropFilter:"blur(4px)" }} onClick={onClose}/>
      <div style={{ background:"#0d0f18", borderTop:"1px solid #141826", borderRadius:"24px 24px 0 0", maxHeight:"75%", display:"flex", flexDirection:"column" }}>
        <div style={{ display:"flex", justifyContent:"center", padding:"10px 0 0" }}><div style={{ width:36, height:4, background:"#1a2035", borderRadius:2 }}/></div>
        <div style={{ padding:"10px 20px 12px", display:"flex", justifyContent:"space-between", alignItems:"center", borderBottom:"1px solid #141826" }}>
          <span style={{ color:"#e8edf5", fontWeight:700, fontSize:15 }}>Comments</span>
          <button onClick={onClose} style={{ background:"none", border:"none", cursor:"pointer" }}>{I.close()}</button>
        </div>
        <div style={{ flex:1, overflowY:"auto", padding:"12px 20px" }}>
          {comments.map((c,i)=>(
            <div key={i} style={{ display:"flex", gap:10, marginBottom:16 }}>
              <Avatar src={c.avatar} initials={c.initials} color={c.color} size={34}/>
              <div style={{ flex:1 }}>
                <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:3 }}>
                  <span style={{ color:"#e8edf5", fontWeight:600, fontSize:12.5 }}>{c.user}</span>
                  <span style={{ color:"#2e3d5a", fontSize:11, fontFamily:"DM Sans" }}>{c.time}</span>
                </div>
                <span style={{ color:"#c8d4e8", fontSize:13, fontFamily:"DM Sans", lineHeight:1.5 }}>{c.text}</span>
              </div>
            </div>
          ))}
        </div>
        <div style={{ padding:"10px 16px 24px", borderTop:"1px solid #141826", display:"flex", gap:10, alignItems:"center" }}>
          <input value={text} onChange={e=>setText(e.target.value)} onKeyDown={e=>e.key==="Enter"&&sendComment()} placeholder="Add a comment..." style={{ flex:1, background:"#141826", border:"1px solid #1a2035", borderRadius:20, padding:"10px 14px", color:"#e8edf5", fontSize:13, fontFamily:"DM Sans", outline:"none" }}/>
          <button onClick={sendComment} style={{ background:"none", border:"none", cursor:"pointer", opacity:text.trim()?1:0.3 }}>{I.send()}</button>
        </div>
      </div>
    </div>
  );
};

